// Order matters
Text(
  "A",
  modifier = Modifier
    .padding(16.dp)            // outer 16dp
    .background(Color.Red)     // red around content + padding
)

Text(
  "A",
  modifier = Modifier
    .background(Color.Red)     // red around content only
    .padding(16.dp)            // 16dp around the red box
)

// Reusable composable accepts Modifier
@Composable
fun PrimaryButton(text: String, modifier: Modifier = Modifier, onClick: () -> Unit) {
  Text(
    text = text,
    modifier = modifier                       // caller's mods first
      .clip(RoundedCornerShape(12.dp))
      .background(Color(0xFF1565C0))
      .clickable { onClick() }
      .padding(horizontal = 16.dp, vertical = 12.dp)
  )
}

// Caller can layer
PrimaryButton("Save", modifier = Modifier.size(width = 200.dp, height = 48.dp)) { save() }

// Custom modifier
fun Modifier.debugBorder(): Modifier = this.then(
  Modifier.border(1.dp, Color.Magenta)
)

@Composable
fun ProductRow(p: Product) {
  Row(
    modifier = Modifier.fillMaxWidth().padding(12.dp),
    verticalAlignment = Alignment.CenterVertically,
    horizontalArrangement = Arrangement.spacedBy(12.dp)
  ) {
    AsyncImage(model = p.image, contentDescription = null, modifier = Modifier.size(48.dp))
    Column(modifier = Modifier.weight(1f)) {                  // weight = take remaining space
      Text(p.name, style = MaterialTheme.typography.titleMedium)
      Text(p.subtitle, style = MaterialTheme.typography.bodySmall)
    }
    Text("$\${p.price}", style = MaterialTheme.typography.titleMedium)
  }
}

// Long list — must use Lazy*
@Composable
fun ProductList(items: List<Product>) {
  LazyColumn(
    contentPadding = PaddingValues(vertical = 8.dp),
    verticalArrangement = Arrangement.spacedBy(4.dp)
  ) {
    items(items, key = { it.id }) { p -> ProductRow(p) }
  }
}

