@Composable
fun Counter() {
  var count by remember { mutableStateOf(0) }
  Column {
    // Only Text reads `count`, so only Text recomposes when count changes.
    Text("Count: \$count")
    Button(onClick = { count++ }) { Text("Increment") }
    HelloHeader()      // never reads count → never recomposes
  }
}

@Composable
fun HelloHeader() = Text("Hello!")

// Side effect example — fire when key changes
@Composable
fun GreetingFor(userId: String) {
  var name by remember { mutableStateOf("") }
  LaunchedEffect(userId) {
    name = api.fetchName(userId)
  }
  Text("Hi, \$name")
}

// Stability — primitives + immutable + @Immutable / @Stable annotated types skip recomposition
@Immutable
data class Profile(val name: String, val avatar: String)

@Composable
fun ProfileCard(p: Profile) {     // Composable can skip if same Profile passed again
  Text(p.name)
}

