import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.foundation.isSystemInDarkTheme
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import android.os.Build

private val LightColors = lightColorScheme(
  primary = Color(0xFF1565C0), onPrimary = Color.White,
  background = Color(0xFFFAFAFA), onBackground = Color(0xFF1A1A1A)
)
private val DarkColors = darkColorScheme(
  primary = Color(0xFF90CAF9), onPrimary = Color(0xFF003258),
  background = Color(0xFF101418), onBackground = Color(0xFFEEEEEE)
)

@Composable
fun AppTheme(
  dynamic: Boolean = true,
  content: @Composable () -> Unit
) {
  val dark = isSystemInDarkTheme()
  val colors = when {
    dynamic && Build.VERSION.SDK_INT >= Build.VERSION_CODES.S -> {
      val ctx = LocalContext.current
      if (dark) dynamicDarkColorScheme(ctx) else dynamicLightColorScheme(ctx)
    }
    dark -> DarkColors
    else -> LightColors
  }
  MaterialTheme(colorScheme = colors, content = content)
}

// Usage
setContent {
  AppTheme { Surface { /* screens */ } }
}

// Custom design tokens via CompositionLocal
data class Spacing(val small: Dp = 4.dp, val medium: Dp = 8.dp, val large: Dp = 16.dp)
val LocalSpacing = staticCompositionLocalOf { Spacing() }

@Composable
fun App() {
  CompositionLocalProvider(LocalSpacing provides Spacing(medium = 12.dp)) {
    Card(modifier = Modifier.padding(LocalSpacing.current.medium)) { /* ... */ }
  }
}

import androidx.compose.runtime.*
import androidx.navigation.compose.*
import androidx.navigation.NavType
import androidx.navigation.navArgument

sealed interface Route {
  data object Home : Route { val path = "home" }
  data object Settings : Route { val path = "settings" }
  data object Profile { fun path(id: Long) = "profile/\$id"; const val template = "profile/{id}" }
}

@Composable
fun AppNav() {
  val navController = rememberNavController()
  NavHost(navController, startDestination = Route.Home.path) {
    composable(Route.Home.path) {
      HomeScreen(
        onProfile = { id -> navController.navigate(Route.Profile.path(id)) },
        onSettings = { navController.navigate(Route.Settings.path) }
      )
    }
    composable(
      route = Route.Profile.template,
      arguments = listOf(navArgument("id") { type = NavType.LongType })
    ) { backStack ->
      val id = backStack.arguments?.getLong("id") ?: 0L
      ProfileScreen(id = id, onBack = { navController.popBackStack() })
    }
    composable(Route.Settings.path) { SettingsScreen() }
  }
}

